package com.seaquake6324.civitas.infrastructure.network;
import com.seaquake6324.civitas.CivitasMod;import java.util.*;import net.minecraft.network.RegistryFriendlyByteBuf;import net.minecraft.network.codec.StreamCodec;import net.minecraft.network.protocol.common.custom.CustomPacketPayload;import net.minecraft.resources.Identifier;
public record ExpansionModePayload(boolean active,UUID cityId,Set<Long> candidates,Set<Long> eligible)implements CustomPacketPayload{private static final UUID EMPTY=new UUID(0,0);public static final Type<ExpansionModePayload> TYPE=new Type<>(Identifier.fromNamespaceAndPath(CivitasMod.MOD_ID,"expansion_mode"));public static final StreamCodec<RegistryFriendlyByteBuf,ExpansionModePayload> STREAM_CODEC=CustomPacketPayload.codec(ExpansionModePayload::write,ExpansionModePayload::read);public ExpansionModePayload{candidates=Set.copyOf(candidates);eligible=Set.copyOf(eligible);}public static ExpansionModePayload stopped(){return new ExpansionModePayload(false,EMPTY,Set.of(),Set.of());}private void write(RegistryFriendlyByteBuf b){b.writeBoolean(active);b.writeUUID(cityId);writeSet(b,candidates);writeSet(b,eligible);}private static ExpansionModePayload read(RegistryFriendlyByteBuf b){return new ExpansionModePayload(b.readBoolean(),b.readUUID(),readSet(b),readSet(b));}private static void writeSet(RegistryFriendlyByteBuf b,Set<Long>s){b.writeVarInt(s.size());s.forEach(b::writeLong);}private static Set<Long> readSet(RegistryFriendlyByteBuf b){int n=b.readVarInt();Set<Long>s=new HashSet<>();for(int i=0;i<n;i++)s.add(b.readLong());return s;}@Override public Type<? extends CustomPacketPayload> type(){return TYPE;}}
